starter:
@property --hue {
  syntax: '<number>';
  inherits: true;
  initial-value: 0;
}

.element {
  background: hsl(var(--hue), 70%, 50%);
  animation: cycleHue 4s linear infinite;
}

@keyframes cycleHue {
  0% { --hue: 0; }
  100% { --hue: 360; }
}

@property --radius-tl { syntax: '<length>'; inherits: false; initial-value: 0px; }
/* Register 3 more corners */

.element {
  border-radius: var(--radius-tl) var(--radius-tr) var(--radius-br) var(--radius-bl);
  animation: morphShape 5s ease-in-out infinite;
}

@property --gradient-angle {
  syntax: '<angle>';
  inherits: false;
  initial-value: 0deg;
}

.element {
  background: linear-gradient(var(--gradient-angle), #e74c3c, #3498db, #2ecc71);
  animation: rotateGradient 6s linear infinite;
}

@keyframes rotateGradient {
  0% { --gradient-angle: 0deg; }
  100% { --gradient-angle: 360deg; }
}

@property --color-primary { syntax: '<color>'; inherits: true; initial-value: #3498db; }
@property --spacing-lg { syntax: '<length>'; inherits: true; initial-value: 2rem; }
/* Register more tokens */

:root { transition: --color-primary 0.5s, --spacing-lg 0.5s; }
[data-theme="dark"] { --color-primary: #8e44ad; }
